    val __bcap = JniErrorHandlerCapture.acquire()
    val __ret = CovNative.unsignedDataMaybe(
        value.byte,
        value.short,
        value.int,
        value.long.toLong(),
        value.maybeLong != null,
        value.maybeLong?.toLong() ?: 0L,
        __bcap,
    )
    if (__bcap.failed) return onError.run(__bcap.ze0)
    return __ret?.let { it.toULong() }
}

