    val __bcap = JniErrorHandlerCapture.acquire()
    val __ret = CovNative.durationOutOfRange(__bcap)
    if (__bcap.failed) return onError.run(__bcap.ze0)
    return __ret.let { if (it == -1L) null else it.toULong() }
